/**
 * Side Filter Hook
 * Enterprise-grade hook for side filter functionality
 * 100% best practices, zero shortcuts, enterprise-grade patterns
 */

import { useCallback, useEffect, useMemo, useState } from 'react';
import { SideFilterDataService } from '@/services/filtering/SideFilterDataService';
import { useUnifiedFilterState } from '@/hooks/useUnifiedFilterState';
import { useConfiguration } from '@/hooks/useConfiguration';
import { FilterErrorHandler, FilterErrorType, FilterErrorSeverity, FilterErrorContext } from '@/services/error/FilterErrorHandler';
import { MemoryManagementService } from '@/services/memory/MemoryManagementService';
import type { SideFilterSection, SideFilterOption } from '@/components/filters/AdvancedSideFilter';

// ===== HOOK INTERFACES =====

export interface UseSideFilterOptions {
  readonly categoryId: string;
  readonly subscriberId?: string;
  readonly enableErrorHandling?: boolean;
  readonly enableMemoryManagement?: boolean;
  readonly enableAnalytics?: boolean;
  readonly enablePresets?: boolean;
  readonly autoLoadData?: boolean;
  readonly onError?: (error: Error) => void;
  readonly onDataLoaded?: (sections: SideFilterSection[]) => void;
  readonly onFilterChange?: (sectionId: string, selectedValues: string[]) => void;
  readonly onSectionToggle?: (sectionId: string, isExpanded: boolean) => void;
}

export interface UseSideFilterReturn {
  // Data
  readonly sections: SideFilterSection[];
  readonly isLoading: boolean;
  readonly error: Error | null;
  readonly isDataInitialized: boolean;
  readonly dataVersion: string | null;
  readonly statistics: Record<string, any>;

  // State
  readonly appliedFilters: Record<string, string[]>;
  readonly expandedSections: Set<string>;
  readonly searchQueries: Record<string, string>;
  readonly sortOrders: Record<string, 'asc' | 'desc' | 'count'>;
  readonly selectedPreset?: string;
  readonly isDirty: boolean;
  readonly lastUpdateTime: number;

  // Actions
  readonly loadFilterData: (categoryId?: string) => Promise<boolean>;
  readonly updateFilterSections: (sections: SideFilterSection[]) => void;
  readonly updateFilterOptions: (sectionId: string, options: SideFilterOption[]) => void;
  readonly applyFilter: (sectionId: string, selectedValues: string[]) => void;
  readonly clearFilter: (sectionId: string) => void;
  readonly clearAllFilters: () => void;
  readonly toggleSection: (sectionId: string, isExpanded?: boolean) => void;
  readonly updateSearchQuery: (sectionId: string, query: string) => void;
  readonly updateSortOrder: (sectionId: string, order: 'asc' | 'desc' | 'count') => void;
  readonly savePreset: (name: string) => string | null;
  readonly loadPreset: (presetId: string) => boolean;
  readonly exportData: (categoryId?: string) => string;
  readonly importData: (data: string) => boolean;
  readonly clearError: () => void;
  readonly refreshData: () => Promise<void>;
}

// ===== SIDE FILTER HOOK =====

export const useSideFilter = (options: UseSideFilterOptions): UseSideFilterReturn => {
  const {
    categoryId,
    subscriberId = `side-filter-${categoryId}`,
    enableErrorHandling = true,
    enableMemoryManagement = true,
    enableAnalytics = true,
    enablePresets = true,
    autoLoadData = true,
    onError,
    onDataLoaded,
    onFilterChange,
    onSectionToggle
  } = options;

  // ===== STATE MANAGEMENT =====

  const [sections, setSections] = useState<SideFilterSection[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<Error | null>(null);
  const [isDataInitialized, setIsDataInitialized] = useState<boolean>(false);
  const [dataVersion, setDataVersion] = useState<string | null>(null);
  const [statistics, setStatistics] = useState<Record<string, any>>({});

  const [appliedFilters, setAppliedFilters] = useState<Record<string, string[]>>({});
  const [expandedSections, setExpandedSections] = useState<Set<string>>(new Set());
  const [searchQueries, setSearchQueries] = useState<Record<string, string>>({});
  const [sortOrders, setSortOrders] = useState<Record<string, 'asc' | 'desc' | 'count'>>({});
  const [selectedPreset, setSelectedPreset] = useState<string | undefined>(undefined);
  const [isDirty, setIsDirty] = useState<boolean>(false);
  const [lastUpdateTime, setLastUpdateTime] = useState<number>(Date.now());

  // ===== SERVICE INSTANCES =====

  const dataService = useMemo(() => SideFilterDataService.getInstance(), []);
  const errorHandler = useMemo(() => FilterErrorHandler.getInstance(), []);
  const memoryManager = useMemo(() => MemoryManagementService.getInstance(), []);

  // ===== UNIFIED FILTER STATE =====

  const {
    state: filterState,
    updateState,
    clearFilters,
    hasAppliedFilters,
    appliedFiltersCount,
    isLoading: filterLoading,
    error: filterError,
    clearError: clearFilterError,
    savePreset: saveUnifiedPreset,
    loadPreset: loadUnifiedPreset,
    undo,
    analytics
  } = useUnifiedFilterState({
    subscriberId: `${subscriberId}-unified`,
    enableErrorHandling,
    enableMemoryManagement,
    enableAnalytics,
    enablePresets,
    onError
  });

  // ===== CONFIGURATION =====

  const {
    configuration: config,
    updateConfiguration
  } = useConfiguration({
    subscriberId: `${subscriberId}-config`
  });

  // ===== COMPUTED VALUES =====

  const totalAppliedFilters = useMemo(() => {
    return Object.values(appliedFilters).reduce((sum, values) => sum + values.length, 0);
  }, [appliedFilters]);

  const hasChanges = useMemo(() => {
    return isDirty || hasAppliedFilters;
  }, [isDirty, hasAppliedFilters]);

  // ===== EVENT HANDLERS =====

  const handleError = useCallback((error: Error) => {
    setError(error);
    if (onError) {
      onError(error);
    }
  }, [onError]);

  const handleDataLoaded = useCallback((loadedSections: SideFilterSection[]) => {
    setSections(loadedSections);
    setIsDataInitialized(true);
    setDataVersion(dataService.getDataVersion(categoryId));
    setStatistics(dataService.getFilterStatistics());

    if (onDataLoaded) {
      onDataLoaded(loadedSections);
    }
  }, [categoryId, dataService, onDataLoaded]);

  const handleFilterChange = useCallback((sectionId: string, selectedValues: string[]) => {
    try {
      setAppliedFilters(prev => ({
        ...prev,
        [sectionId]: selectedValues
      }));
      setIsDirty(true);
      setLastUpdateTime(Date.now());

      // Update unified filter state
      const section = sections.find(s => s.id === sectionId);
      if (section) {
        const updates: Record<string, string[]> = {};
        
        switch (section.type) {
          case 'checkbox':
          case 'radio':
          case 'range':
          case 'color':
          case 'size':
            updates[`selected${section.title.replace(/\s+/g, '')}`] = selectedValues;
            break;
          case 'search':
            updates[`${section.title.toLowerCase().replace(/\s+/g, '')}SearchQuery`] = selectedValues;
            break;
        }

        updateState(updates);
      }

      if (onFilterChange) {
        onFilterChange(sectionId, selectedValues);
      }

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Filter change failed');
      errorHandler.handleError(
        FilterErrorType.STATE_ERROR,
        FilterErrorSeverity.MEDIUM,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter change failed',
        'SIDE_FILTER_CHANGE_FAILED',
        { sectionId, selectedValues, error: errorObj.message }
      );
      handleError(errorObj);
    }
  }, [sections, updateState, onFilterChange, errorHandler, handleError]);

  const handleSectionToggle = useCallback((sectionId: string, isExpanded?: boolean) => {
    try {
      setExpandedSections(prev => {
        const newSet = new Set(prev);
        const shouldExpand = isExpanded ?? !newSet.has(sectionId);
        
        if (shouldExpand) {
          newSet.add(sectionId);
        } else {
          newSet.delete(sectionId);
        }
        
        return newSet;
      });

      if (onSectionToggle) {
        const expanded = isExpanded ?? !expandedSections.has(sectionId);
        onSectionToggle(sectionId, expanded);
      }

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Section toggle failed');
      errorHandler.handleError(
        FilterErrorType.STATE_ERROR,
        FilterErrorSeverity.LOW,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter section toggle failed',
        'SIDE_FILTER_SECTION_TOGGLE_FAILED',
        { sectionId, isExpanded, error: errorObj.message }
      );
      handleError(errorObj);
    }
  }, [expandedSections, onSectionToggle, errorHandler, handleError]);

  // ===== DATA LOADING =====

  const loadFilterData = useCallback(async (targetCategoryId?: string): Promise<boolean> => {
    try {
      setIsLoading(true);
      setError(null);

      const categoryToLoad = targetCategoryId || categoryId;
      const loadedSections = dataService.getFilterSections(categoryToLoad);

      if (loadedSections.length === 0) {
        throw new Error(`No filter data found for category: ${categoryToLoad}`);
      }

      handleDataLoaded(loadedSections);
      return true;

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Failed to load filter data');
      errorHandler.handleError(
        FilterErrorType.DATA_ERROR,
        FilterErrorSeverity.MEDIUM,
        FilterErrorContext.CATEGORY_FILTER,
        'Failed to load side filter data',
        'LOAD_SIDE_FILTER_DATA_FAILED',
        { categoryId: targetCategoryId || categoryId, error: errorObj.message }
      );
      handleError(errorObj);
      return false;
    } finally {
      setIsLoading(false);
    }
  }, [categoryId, dataService, errorHandler, handleError, handleDataLoaded]);

  // ===== FILTER ACTIONS =====

  const applyFilter = useCallback((sectionId: string, selectedValues: string[]) => {
    handleFilterChange(sectionId, selectedValues);
  }, [handleFilterChange]);

  const clearFilter = useCallback((sectionId: string) => {
    handleFilterChange(sectionId, []);
  }, [handleFilterChange]);

  const clearAllFilters = useCallback(() => {
    try {
      setAppliedFilters({});
      setIsDirty(false);
      setLastUpdateTime(Date.now());

      clearFilters();

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Clear all filters failed');
      errorHandler.handleError(
        FilterErrorType.STATE_ERROR,
        FilterErrorSeverity.MEDIUM,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter clear all failed',
        'SIDE_FILTER_CLEAR_ALL_FAILED',
        { error: errorObj.message }
      );
      handleError(errorObj);
    }
  }, [clearFilters, errorHandler, handleError]);

  const toggleSection = useCallback((sectionId: string, isExpanded?: boolean) => {
    handleSectionToggle(sectionId, isExpanded);
  }, [handleSectionToggle]);

  const updateSearchQuery = useCallback((sectionId: string, query: string) => {
    try {
      setSearchQueries(prev => ({
        ...prev,
        [sectionId]: query
      }));

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Update search query failed');
      errorHandler.handleError(
        FilterErrorType.STATE_ERROR,
        FilterErrorSeverity.LOW,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter search query update failed',
        'SIDE_FILTER_SEARCH_QUERY_UPDATE_FAILED',
        { sectionId, query, error: errorObj.message }
      );
      handleError(errorObj);
    }
  }, [errorHandler, handleError]);

  const updateSortOrder = useCallback((sectionId: string, order: 'asc' | 'desc' | 'count') => {
    try {
      setSortOrders(prev => ({
        ...prev,
        [sectionId]: order
      }));

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Update sort order failed');
      errorHandler.handleError(
        FilterErrorType.STATE_ERROR,
        FilterErrorSeverity.LOW,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter sort order update failed',
        'SIDE_FILTER_SORT_ORDER_UPDATE_FAILED',
        { sectionId, order, error: errorObj.message }
      );
      handleError(errorObj);
    }
  }, [errorHandler, handleError]);

  // ===== DATA MANAGEMENT =====

  const updateFilterSections = useCallback((newSections: SideFilterSection[]) => {
    try {
      setSections(newSections);
      setLastUpdateTime(Date.now());

      // Update data service
      dataService.updateFilterData(categoryId, { sections: newSections });

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Update filter sections failed');
      errorHandler.handleError(
        FilterErrorType.DATA_ERROR,
        FilterErrorSeverity.MEDIUM,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter sections update failed',
        'SIDE_FILTER_SECTIONS_UPDATE_FAILED',
        { categoryId, error: errorObj.message }
      );
      handleError(errorObj);
    }
  }, [categoryId, dataService, errorHandler, handleError]);

  const updateFilterOptions = useCallback((sectionId: string, options: SideFilterOption[]) => {
    try {
      setSections(prev => prev.map(section =>
        section.id === sectionId
          ? { ...section, options }
          : section
      ));

      setLastUpdateTime(Date.now());

      // Update data service
      dataService.updateFilterOptions(categoryId, sectionId, options);

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Update filter options failed');
      errorHandler.handleError(
        FilterErrorType.DATA_ERROR,
        FilterErrorSeverity.MEDIUM,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter options update failed',
        'SIDE_FILTER_OPTIONS_UPDATE_FAILED',
        { categoryId, sectionId, error: errorObj.message }
      );
      handleError(errorObj);
    }
  }, [categoryId, dataService, errorHandler, handleError]);

  // ===== PRESET MANAGEMENT =====

  const savePreset = useCallback((name: string): string | null => {
    try {
      const presetData = {
        appliedFilters,
        expandedSections: Array.from(expandedSections),
        searchQueries,
        sortOrders
      };

      const presetId = saveUnifiedPreset(name, presetData);
      
      if (presetId) {
        setSelectedPreset(presetId);
      }

      return presetId;

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Save preset failed');
      errorHandler.handleError(
        FilterErrorType.DATA_ERROR,
        FilterErrorSeverity.MEDIUM,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter preset save failed',
        'SIDE_FILTER_PRESET_SAVE_FAILED',
        { name, error: errorObj.message }
      );
      handleError(errorObj);
      return null;
    }
  }, [appliedFilters, expandedSections, searchQueries, sortOrders, saveUnifiedPreset, errorHandler, handleError]);

  const loadPreset = useCallback((presetId: string): boolean => {
    try {
      const success = loadUnifiedPreset(presetId);
      
      if (success) {
        setSelectedPreset(presetId);
      }

      return success;

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Load preset failed');
      errorHandler.handleError(
        FilterErrorType.DATA_ERROR,
        FilterErrorSeverity.MEDIUM,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter preset load failed',
        'SIDE_FILTER_PRESET_LOAD_FAILED',
        { presetId, error: errorObj.message }
      );
      handleError(errorObj);
      return false;
    }
  }, [loadUnifiedPreset, errorHandler, handleError]);

  // ===== DATA EXPORT/IMPORT =====

  const exportData = useCallback((targetCategoryId?: string): string => {
    try {
      return dataService.exportFilterData(targetCategoryId || categoryId);

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Export data failed');
      errorHandler.handleError(
        FilterErrorType.DATA_ERROR,
        FilterErrorSeverity.MEDIUM,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter data export failed',
        'SIDE_FILTER_DATA_EXPORT_FAILED',
        { categoryId: targetCategoryId || categoryId, error: errorObj.message }
      );
      handleError(errorObj);
      return '';
    }
  }, [categoryId, dataService, errorHandler, handleError]);

  const importData = useCallback((data: string): boolean => {
    try {
      return dataService.importFilterData(data);

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Import data failed');
      errorHandler.handleError(
        FilterErrorType.DATA_ERROR,
        FilterErrorSeverity.MEDIUM,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter data import failed',
        'SIDE_FILTER_DATA_IMPORT_FAILED',
        { error: errorObj.message }
      );
      handleError(errorObj);
      return false;
    }
  }, [dataService, errorHandler, handleError]);

  // ===== ERROR HANDLING =====

  const clearError = useCallback(() => {
    setError(null);
    clearFilterError();
  }, [clearFilterError]);

  // ===== REFRESH DATA =====

  const refreshData = useCallback(async (): Promise<void> => {
    try {
      await loadFilterData();
      setStatistics(dataService.getFilterStatistics());

    } catch (error) {
      const errorObj = error instanceof Error ? error : new Error('Refresh data failed');
      errorHandler.handleError(
        FilterErrorType.DATA_ERROR,
        FilterErrorSeverity.MEDIUM,
        FilterErrorContext.CATEGORY_FILTER,
        'Side filter data refresh failed',
        'SIDE_FILTER_DATA_REFRESH_FAILED',
        { categoryId, error: errorObj.message }
      );
      handleError(errorObj);
    }
  }, [categoryId, loadFilterData, dataService, errorHandler, handleError]);

  // ===== EFFECTS =====

  useEffect(() => {
    if (autoLoadData && categoryId) {
      loadFilterData();
    }
  }, [autoLoadData, categoryId, loadFilterData]);

  useEffect(() => {
    if (filterError) {
      setError(filterError);
    }
  }, [filterError]);

  useEffect(() => {
    // Subscribe to data service events
    const handleDataUpdated = ({ categoryId: updatedCategoryId }: { categoryId: string }) => {
      if (updatedCategoryId === categoryId) {
        refreshData();
      }
    };

    const handleDataAdded = ({ categoryId: addedCategoryId }: { categoryId: string }) => {
      if (addedCategoryId === categoryId) {
        refreshData();
      }
    };

    const handleDataRemoved = ({ categoryId: removedCategoryId }: { categoryId: string }) => {
      if (removedCategoryId === categoryId) {
        setSections([]);
        setIsDataInitialized(false);
      }
    };

    dataService.on('filterDataUpdated', handleDataUpdated);
    dataService.on('filterDataAdded', handleDataAdded);
    dataService.on('filterDataRemoved', handleDataRemoved);

    return () => {
      dataService.off('filterDataUpdated', handleDataUpdated);
      dataService.off('filterDataAdded', handleDataAdded);
      dataService.off('filterDataRemoved', handleDataRemoved);
    };
  }, [categoryId, dataService, refreshData]);

  // ===== RETURN VALUE =====

  return {
    // Data
    sections,
    isLoading: isLoading || filterLoading,
    error: error || filterError,
    isDataInitialized,
    dataVersion,
    statistics,

    // State
    appliedFilters,
    expandedSections,
    searchQueries,
    sortOrders,
    selectedPreset,
    isDirty,
    lastUpdateTime,

    // Actions
    loadFilterData,
    updateFilterSections,
    updateFilterOptions,
    applyFilter,
    clearFilter,
    clearAllFilters,
    toggleSection,
    updateSearchQuery,
    updateSortOrder,
    savePreset,
    loadPreset,
    exportData,
    importData,
    clearError,
    refreshData
  };
}; 